#include <iostream>
#include <vector>

using namespace std;

void dfs(int current, vector<vector<int>> &adj, vector<bool> &visited)
{
    visited[current] = true;
    cout << current << " ";

    for (int neighbor : adj[current])
    {
        if (!visited[neighbor])
        {
            dfs(neighbor, adj, visited); // commit FULLY to this neighbor before trying the next
        }
    }
}

int main()
{
    int vertices = 5;
    vector<vector<int>> adj(vertices);

    adj[0] = {1, 2};
    adj[1] = {0, 3};
    adj[2] = {0, 3};
    adj[3] = {1, 2, 4};
    adj[4] = {3};

    vector<bool> visited(vertices, false);

    dfs(0, adj, visited);

    return 0;
}

